// ---------------------------------------------------------------------------
// MCP auto-registration
// ---------------------------------------------------------------------------
function _displayPath(p, cwd) {
  return p.startsWith(os.homedir()) ? '~' + p.slice(os.homedir().length) : path.relative(cwd, p);
}

function _registerMcpJson(filePath, serverEntry, cwd) {
  if (!fs.existsSync(filePath)) return;
  try {
    const raw = fs.readFileSync(filePath, 'utf8');
    const settings = JSON.parse(raw);
    if (!settings.mcpServers) settings.mcpServers = {};
    if (settings.mcpServers['sigmap']) return;
    settings.mcpServers['sigmap'] = serverEntry;
    fs.writeFileSync(filePath, JSON.stringify(settings, null, 2) + '\n');
    console.warn(`[sigmap] registered MCP server in ${_displayPath(filePath, cwd)}`);
  } catch (err) {
    console.warn(`[sigmap] could not update ${_displayPath(filePath, cwd)}: ${err.message}`);
  }
}

function _registerCodexYaml(filePath, scriptPath) {
  if (!fs.existsSync(filePath)) return;
  try {
    const raw = fs.readFileSync(filePath, 'utf8');
    if (raw.includes('sigmap')) return; // already registered
    const yamlBlock = [
      '',
      'mcpServers:',
      '  sigmap:',
      `    command: node`,
      `    args:`,
      `      - ${path.resolve(scriptPath)}`,
      `      - --mcp`,
    ].join('\n');
    fs.writeFileSync(filePath, raw.trimEnd() + yamlBlock + '\n');
    console.warn('[sigmap] registered MCP server in ~/.codex/config.yaml');
  } catch (err) {
    console.warn(`[sigmap] could not update ~/.codex/config.yaml: ${err.message}`);
  }
}

function registerMcp(cwd, scriptPath) {
  const serverEntry = {
    command: 'node',
    args: [path.resolve(scriptPath), '--mcp'],
  };

  // JSON mcpServers targets: portable .mcp.json (priority), Claude, Cursor,
  // Windsurf project, Windsurf global, VS Code (GitHub Copilot 1.99+),
  // OpenCode project, OpenCode global, Gemini CLI
  const jsonTargets = [
    path.join(cwd, '.mcp.json'),
    path.join(cwd, '.claude', 'settings.json'),
    path.join(cwd, '.cursor', 'mcp.json'),
    path.join(cwd, '.windsurf', 'mcp.json'),
    path.join(os.homedir(), '.codeium', 'windsurf', 'mcp_config.json'),
    path.join(cwd, '.vscode', 'mcp.json'),
    path.join(cwd, 'opencode.json'),
    path.join(os.homedir(), '.config', 'opencode', 'config.json'),
    path.join(os.homedir(), '.gemini', 'settings.json'),
  ];

  for (const target of jsonTargets) {
    _registerMcpJson(target, serverEntry, cwd);
  }

  // Zed uses context_servers (different shape from mcpServers)
  const zedSettingsPath = path.join(os.homedir(), '.config', 'zed', 'settings.json');
  if (fs.existsSync(zedSettingsPath)) {
    try {
      const raw      = fs.readFileSync(zedSettingsPath, 'utf8');
      const settings = JSON.parse(raw);
      if (!settings.context_servers) settings.context_servers = {};
      if (!settings.context_servers['sigmap']) {
        settings.context_servers['sigmap'] = {
          command: { path: 'node', args: [path.resolve(scriptPath), '--mcp'] },
        };
        fs.writeFileSync(zedSettingsPath, JSON.stringify(settings, null, 2) + '\n');
        console.warn('[sigmap] registered context server in ~/.config/zed/settings.json');
      }
    } catch (err) {
      console.warn(`[sigmap] could not update ~/.config/zed/settings.json: ${err.message}`);
    }
  }

  // Codex CLI uses YAML (~/.codex/config.yaml)
  _registerCodexYaml(path.join(os.homedir(), '.codex', 'config.yaml'), scriptPath);

  // Print manual snippets for all targets
  console.warn('[sigmap] MCP / context server config snippets:');
  console.warn('  .mcp.json (portable, recommended):');
  console.warn(JSON.stringify({ mcpServers: { sigmap: serverEntry } }, null, 2));
  console.warn('  Claude / Cursor / Windsurf / VS Code / OpenCode / Gemini CLI:');
  console.warn(JSON.stringify({ mcpServers: { sigmap: serverEntry } }, null, 2));
  console.warn('  Zed (~/.config/zed/settings.json):');
  console.warn(JSON.stringify({ context_servers: { sigmap: { command: { path: 'node', args: [path.resolve(scriptPath), '--mcp'] } } } }, null, 2));
  console.warn('  Codex CLI (~/.codex/config.yaml):');
  console.warn([
    'mcpServers:',
    '  sigmap:',
    `    command: node`,
    `    args:`,
    `      - ${path.resolve(scriptPath)}`,
    `      - --mcp`,
  ].join('\n'));
}

// ---------------------------------------------------------------------------
// v4.2 helpers
// ---------------------------------------------------------------------------
const MODEL_COSTS = {
  'gpt-4':             0.030,
  'gpt-4o':            0.005,
  'gpt-4o-mini':       0.000150,
  'claude-3-5-sonnet': 0.003,
  'claude-3-haiku':    0.00025,
  'claude-opus-4':     0.015,
  'gemini-1.5-pro':    0.00125,
};

function buildMiniContext(ranked, cwd) {
  const lines = ['# SigMap Query Context', `Generated: ${new Date().toISOString()}`, ''];
  for (const { file, sigs } of ranked) {
    lines.push(`## ${file}`, '```', ...sigs.slice(0, 20), '```', '');
  }
  return lines.join('\n');
}

// Surgical Context Phase 2 (v6.12.0): collapse one signature to a symbol-header
// pointer — `<declaration head>  :start-end` — dropping param lists, return types,
// and any body so the agent fetches the real lines on demand via the get_lines MCP tool.
function toIndexLine(sig) {
  if (typeof sig !== 'string') return '';
  // Anchor is `:start-end`, optionally followed by a `# doc hint` (Python extractor).
  const m = sig.match(/\s*:(\d+)-(\d+)(?:\s*#.*)?\s*$/);
  if (!m) {
    // No anchor (e.g. an indented member) — keep a trimmed head so it stays listed.
    return sig.trim().slice(0, 60);
  }
  const range = `:${m[1]}-${m[2]}`;
  let head = sig.slice(0, m.index).trim();
  const paren = head.indexOf('(');
  if (paren > 0) head = head.slice(0, paren).trim();      // drop params
  head = head.replace(/\s*[=→].*$/, '').trim();           // drop return type / assignment tail
  return head ? `${head}  ${range}` : range;
}

// Two-tier index output: emit only `file → [symbol:start-end]` headers (no bodies).
function buildIndexContext(ranked, cwd) {
  const lines = [
    '# SigMap Query Context (index mode)',
    `Generated: ${new Date().toISOString()}`,
    '> Symbol index only — fetch exact lines on demand via the `get_lines` MCP tool.',
    '',
  ];
  for (const { file, sigs } of ranked) {
    const idx = sigs.slice(0, 40).map(toIndexLine).filter(Boolean);
    lines.push(`## ${file}`, '```', ...idx, '```', '');
  }
  return lines.join('\n');
}

function computeCurrentRisk(cwd) {
  try {
    const out = __git(['diff', '--name-only', 'HEAD'], { cwd, timeout: 3000 });
    const count = out.trim().split('\n').filter(Boolean).length;
    if (count === 0) return 'NONE';
    if (count <= 3)  return 'LOW';
    if (count <= 10) return 'MEDIUM';
    return 'HIGH';
  } catch (_) { return 'UNKNOWN'; }
}

function getRawTokenCount(cwd, config) {
  let total = 0;
  const files = buildFileList(cwd, config);
  for (const fp of files) {
    try { total += estimateTokens(fs.readFileSync(fp, 'utf8')); } catch (_) {}
  }
  return total;
}

function getIntentWeights(intent) {
  const { DEFAULT_WEIGHTS } = requireSourceOrBundled('./src/retrieval/ranker');
  const base = Object.assign({}, DEFAULT_WEIGHTS);
  if (intent === 'debug')    return Object.assign({}, base, { recencyBoost: base.recencyBoost * 1.5 });
  if (intent === 'explain')  return Object.assign({}, base, { symbolMatch:  base.symbolMatch  * 1.5 });
  if (intent === 'refactor') return Object.assign({}, base, { pathMatch:    base.pathMatch    * 1.5 });
  if (intent === 'review')   return Object.assign({}, base, { exactToken:   base.exactToken   * 1.3 });
  return base;
}

function extractQuerySymbols(query) {
  return (query.match(/\b[A-Z][a-zA-Z]+|[a-z]+(?:[A-Z][a-z]+)+\b/g) || []);
}

function collectLearnFiles(args, flag, cwd) {
  const idx = args.indexOf(flag);
  if (idx < 0) return { rawCount: 0, files: [], warnings: [] };

  const { normalizeFile } = requireSourceOrBundled('./src/learning/weights');
  const seen = new Set();
  const files = [];
  const warnings = [];
  let rawCount = 0;

  for (let i = idx + 1; i < args.length; i++) {
    const value = args[i];
    if (!value || value.startsWith('--')) break;
    rawCount++;
    const normalized = normalizeFile(cwd, value);
    if (!normalized) {
      warnings.push(`${value} is outside the repo`);
      continue;
    }
    if (!fs.existsSync(path.join(cwd, normalized))) {
      warnings.push(`${normalized} does not exist`);
      continue;
    }
    if (!seen.has(normalized)) {
      seen.add(normalized);
      files.push(normalized);
    }
  }

  return { rawCount, files, warnings };
}

function main() {
  const args = process.argv.slice(2);

  // Feature 1: `sigmap run` alias — strip positional 'run' so existing logic handles it
  if (args[0] === 'run' && !args[0].startsWith('--')) {
    args.shift();
  }

  const invokedFrom = process.cwd();

  // --cwd <dir>: restrict scanning to that directory instead of the project root
  const cwdFlagIdx = args.indexOf('--cwd');
  const cwdFlag = cwdFlagIdx !== -1 ? (args[cwdFlagIdx + 1] || '').trim() : null;
  if (cwdFlag !== null && (!cwdFlag || cwdFlag.startsWith('--'))) {
    console.error('[sigmap] --cwd requires a directory path');
    process.exit(1);
  }
  const cwd = cwdFlag
    ? path.resolve(invokedFrom, cwdFlag)
    : resolveProjectRoot(invokedFrom);
  // v7.0.1: remember the invocation root so the generation star-nudge always tracks
  // usage at the repo root, even when runGenerate is called per-package (monorepo).
  global.__sigmapRootCwd = cwd;
  const scriptPath = process.argv[1] || path.join(invokedFrom, 'gen-context.js');

  if (cwdFlag) {
    if (!fs.existsSync(cwd)) {
      console.error(`[sigmap] --cwd directory does not exist: ${cwd}`);
      process.exit(1);
    }
    if (!fs.statSync(cwd).isDirectory()) {
      console.error(`[sigmap] --cwd must be a directory, not a file: ${cwd}`);
      process.exit(1);
    }
    console.warn(`[sigmap] --cwd: restricting scan to ${cwd}`);
  } else if (cwd !== invokedFrom) {
    console.warn(`[sigmap] using project root: ${cwd}`);
  }

  if (args.includes('--help') || args.includes('-h')) {
    printHelp(detectInvokedAs());
    process.exit(0);
  }

  if (args.includes('--version') || args.includes('-v')) {
    console.log(VERSION);
    process.exit(0);
  }

  // MCP server — start before loading config (reads files on demand)
  if (args.includes('--mcp')) {
    const { start } = __require('./src/mcp/server');
    start(cwd);
    return; // keep process alive — server drives lifecycle via stdin
  }

  const config = loadConfig(cwd);

  // --cwd restricts scanning: override srcDirs so only the given directory is scanned
  if (cwdFlag) {
    config.srcDirs = ['.'];
  }

  // --coverage: enable test coverage annotation without editing config
  if (args.includes('--coverage')) {
    config.testCoverage = true;
  }

  // ── --output <file> — parse early so every subsequent block can use it ─────
  // Resolves the custom output path and merges it into config.customOutput.
  // Also persists the resolved relative path to gen-context.config.json so
  // future --query calls (without --output) find the file automatically.
  (function resolveOutputFlag() {
    const outIdx = args.indexOf('--output');
    if (outIdx < 0) return;
    const raw = (args[outIdx + 1] || '').trim();
    if (!raw || raw.startsWith('--')) {
      console.error('[sigmap] --output requires a file path');
      console.error('  Example: node gen-context.js --output .context/ai-context.md');
      process.exit(1);
    }
    const abs  = path.resolve(cwd, raw);
    const rel  = path.relative(cwd, abs);
    config.customOutput = rel; // consumed by runGenerate

    // Persist to gen-context.config.json for future --query calls
    const cfgPath = path.join(cwd, 'gen-context.config.json');
    try {
      let savedCfg = {};
      if (fs.existsSync(cfgPath)) {
        try { savedCfg = JSON.parse(fs.readFileSync(cfgPath, 'utf8')); } catch (_) {}
      }
      if (savedCfg.customOutput !== rel) {
        savedCfg.customOutput = rel;
        fs.writeFileSync(cfgPath, JSON.stringify(savedCfg, null, 2) + '\n', 'utf8');
      }
    } catch (err) {
      console.warn(`[sigmap] could not persist customOutput to config: ${err.message}`);
    }
  })();

  // Feature 2: `--mode fast|full|both`
  const modeIdx = args.indexOf('--mode');
  const mode = modeIdx !== -1
    ? args[modeIdx + 1]
    : (config.mode || 'default');
  const VALID_MODES = ['default', 'fast', 'full', 'both', 'index'];
  if (mode && !VALID_MODES.includes(mode)) {
    console.error(`[sigmap] unknown --mode "${mode}". Valid: ${VALID_MODES.join(', ')}`);
    process.exit(1);
  }

  // v4.2: `sigmap ask "<query>"` — unified pipeline
  if (args[0] === 'ask') {
    const __askT0 = Date.now();
    // v6.8: Handle --followup flag which may appear before or after query
    let query = args[1];
    if (query === '--followup' && args[2]) {
      query = args[2];
    } else if (query && query.startsWith('--') && query !== '--json' && query !== '--model') {
      // Allow --json and --model but not other flags as query
      console.error('[sigmap] Usage: sigmap ask "<query>" [--followup] [--json] [--model <name>]');
      console.error('  Example: sigmap ask "fix the login bug" --followup');
      process.exit(1);
    }
    if (!query || query.startsWith('--')) {
      console.error('[sigmap] Usage: sigmap ask "<query>" [--followup] [--json] [--model <name>]');
      console.error('  Example: sigmap ask "fix the login bug" --followup');
      process.exit(1);
    }

    const { detectIntent, buildSigIndex, rank } = requireSourceOrBundled('./src/retrieval/ranker');
    const { coverageScore } = requireSourceOrBundled('./src/analysis/coverage-score');
    const { loadSession, saveSession, mergeSessionContext } = requireSourceOrBundled('./src/session/memory');
    const { detectWorkspaces, inferPackage, scopeToPackage } = requireSourceOrBundled('./src/workspace/detector');

    let intent = detectIntent(query);
    let intentWeights = getIntentWeights(intent);

    const sigIndex = buildSigIndex(cwd);
    if (sigIndex.size === 0) {
      console.error('[sigmap] no context file found. Run: sigmap  (to generate first)');
      process.exit(1);
    }

    // v7.0.0: Squeeze — classify and minimize pasted stacktrace/CI-log/JSON
    // input before ranking. Always runs silently; only prompts (interactive
    // TTY) when the reduction clears the threshold. Never blocks pipes/CI.
    let squeezeOffered = false;
    let squeezeAccepted = false;
    if (!args.includes('--no-squeeze')) {
      try {
        const { squeeze: runSqueeze, shouldPrompt, formatSummary } = requireSourceOrBundled('./src/squeeze/index');
        const sq = runSqueeze(query, { srcDirs: config.srcDirs, symbolIndex: sigIndex });
        if (sq.applies && sq.reduction > 0) {
          squeezeOffered = true;
          const thrIdx = args.indexOf('--squeeze-threshold');
          const threshold = thrIdx !== -1 ? parseFloat(args[thrIdx + 1]) : 30;
          const auto = args.includes('--squeeze');
          const interactive = !!(process.stdin.isTTY && process.stderr.isTTY) && !args.includes('--json');
          let accept = false;
          if (auto) {
            accept = true;
          } else if (interactive && shouldPrompt(sq.reduction, threshold)) {
            process.stderr.write('\n' + formatSummary(sq) + '\n\n');
            process.stderr.write('Proceed with minimized input? [Y/n] ');
            const buf = Buffer.alloc(8);
            try {
              const n = fs.readSync(0, buf, 0, 8, null);
              const ans = buf.toString('utf8', 0, n).trim().toLowerCase();
              accept = ans === '' || ans === 'y' || ans === 'yes';
            } catch (_) { accept = false; }
          }
          if (accept) {
            query = sq.squeezed;
            intent = detectIntent(query);
            intentWeights = getIntentWeights(intent);
            squeezeAccepted = true;
          }
        }
      } catch (_) { /* squeeze is best-effort — never break ask */ }
    }

    let ranked = rank(query, sigIndex, { topK: 5, weights: intentWeights, cwd });

    // v6.10: Workspace scoping — infer package from query and apply boost
    const workspaces = detectWorkspaces(cwd);
    const packageFlag = args[args.indexOf('--package') + 1];
    const globalFlag = args.includes('--global');

    let inferredPackage = null;
    if (!globalFlag && workspaces.length > 0) {
      if (packageFlag) {
        inferredPackage = workspaces.find(d => path.basename(d) === packageFlag) || null;
        if (!packageFlag || !inferredPackage) {
          process.stderr.write(`[sigmap] ⚠  package "${packageFlag}" not found — searching entire repo\n`);
        }
      } else {
        inferredPackage = inferPackage(query, workspaces, cwd);
      }
    }

    if (inferredPackage) {
      ranked = ranked.map(r => ({
        ...r,
        score: r.score + scopeToPackage(r.file, inferredPackage),
      })).sort((a, b) => b.score - a.score);

      if (!args.includes('--json') && !globalFlag) {
        process.stderr.write(`[sigmap] 📦 package scope: ${path.relative(cwd, inferredPackage)}\n`);
      }
    }

    // v6.8: --followup support — carry session context forward
    const isFollowup = args.includes('--followup');
    const session = isFollowup ? loadSession(cwd) : null;
    if (session) {
      ranked = mergeSessionContext(ranked, session, intent);
      ranked.sort((a, b) => b.score - a.score);
      if (!args.includes('--json')) {
        process.stderr.write(`[sigmap] ♻  followup — carrying context from: "${session.lastQuery.slice(0, 60)}"\n`);
      }
    }

    // v6.12: Delta context — restrict to files changed since a git ref (--since <ref>).
    const sinceIdx = args.indexOf('--since');
    if (sinceIdx !== -1 && args[sinceIdx + 1]) {
      const baseRef = args[sinceIdx + 1];
      const changed = getFilesChangedSinceBase(cwd, baseRef);
      const before = ranked.length;
      ranked = ranked.filter((r) => changed.has(path.resolve(cwd, r.file)));
      if (!args.includes('--json')) {
        process.stderr.write(`[sigmap] Δ since ${baseRef}: ${ranked.length}/${before} ranked files changed\n`);
      }
    }

    // v6.8: Save session for future --followup calls
    saveSession(cwd, { intent, topFiles: ranked.slice(0, 5).map(r => ({ file: r.file, score: r.score })), query });
    // v6.12: Two-tier output — `--mode index` emits symbol pointers only (bodies via get_lines).
    const indexMode = mode === 'index' || args.includes('--index');
    const miniCtx = indexMode ? buildIndexContext(ranked, cwd) : buildMiniContext(ranked, cwd);
    const outPath = path.join(cwd, '.context', 'query-context.md');
    fs.mkdirSync(path.dirname(outPath), { recursive: true });
    fs.writeFileSync(outPath, miniCtx, 'utf8');
    const ctxTok = estimateTokens(miniCtx);

    const allFiles = buildFileList(cwd, config);
    const fakeEntries = allFiles.map((f) => ({ filePath: f }));
    let coveragePct = 0;
    try { coveragePct = coverageScore(cwd, fakeEntries, config).score; } catch (_) {}

    // Realistic baseline: the full content of the files SigMap actually surfaced
    // for this query. Without SigMap you'd read these files in full; SigMap gives
    // you their signatures instead — so this is the true per-query saving. Falls
    // back to the whole-repo count only if nothing ranked.
    let rawTok = 0;
    for (const r of ranked) {
      try { rawTok += estimateTokens(fs.readFileSync(path.join(cwd, r.file), 'utf8')); } catch (_) {}
    }
    if (rawTok === 0) rawTok = getRawTokenCount(cwd, config);
    const savings = rawTok > 0 ? Math.round((1 - ctxTok / rawTok) * 100) : 0;
    const model = args[args.indexOf('--model') + 1] || 'gpt-4o';
    const rateK = MODEL_COSTS[model] || MODEL_COSTS['gpt-4o'];
    const costRaw = ((rawTok / 1000) * rateK).toFixed(4);
    const costCtx = ((ctxTok / 1000) * rateK).toFixed(4);

    const riskLevel = computeCurrentRisk(cwd);

    if (args.includes('--json')) {
      process.stdout.write(JSON.stringify({
        intent, coverage: coveragePct, contextTokens: ctxTok,
        costBefore: costRaw, costAfter: costCtx, savingsPct: savings,
        riskLevel, contextPath: path.relative(cwd, outPath),
      }) + '\n');
    } else {
      if (coveragePct < 70) {
        process.stderr.write(`[sigmap] ⚠  coverage ${coveragePct}% — consider running: sigmap validate\n`);
      }
      const bar = '─'.repeat(44);
      console.log([
        bar,
        ` sigmap ask  "${query}"`,
        ` Intent    : ${intent}`,
        ` Context   : ${ctxTok.toLocaleString()} tokens  →  ${path.relative(cwd, outPath)}`,
        ` Coverage  : ${coveragePct}%`,
        ` Risk      : ${riskLevel}`,
        ` Cost      : $${costCtx}/query  (was $${costRaw} · saved ${savings}%)`,
        bar,
      ].join('\n'));
    }
    // gain: capture this query's savings for the `sigmap gain` dashboard.
    try {
      const { recordUsage, isTrackingEnabled } = requireSourceOrBundled('./src/tracking/logger');
      if (isTrackingEnabled(config, args)) {
        recordUsage({
          version: VERSION,
          op: 'ask',
          baselineTokens: rawTok,
          actualTokens: ctxTok,
          durationMs: Date.now() - __askT0,
          model,
        }, cwd);
      }
    } catch (_) { /* gain capture is best-effort */ }

    // v7.0.0: record the run and show the one-time star nudge (interactive only).
    try {
      const { checkStarNudge } = requireSourceOrBundled('./src/nudge');
      const showNudge = !!process.stderr.isTTY && !args.includes('--json');
      checkStarNudge(cwd, true, {
        silent: !showNudge,
        bump: { squeezeOffered: squeezeOffered ? 1 : 0, squeezeAccepted: squeezeAccepted ? 1 : 0 },
      });
    } catch (_) {}
    process.exit(0);
  }

  // `sigmap gain` — token-savings dashboard (totals, by-operation, trends).
  if (args[0] === 'gain') {
    const valOf = (f, d) => { const i = args.indexOf(f); return i >= 0 && args[i + 1] ? args[i + 1] : d; };
    if (args.includes('--reset')) {
      try {
        const { GAIN_FILE } = requireSourceOrBundled('./src/tracking/logger');
        const p = path.join(cwd, GAIN_FILE);
        if (fs.existsSync(p)) fs.unlinkSync(p);
        console.log('[sigmap] gain: usage log cleared.');
      } catch (e) { console.error(`[sigmap] gain: ${e.message}`); }
      process.exit(0);
    }
    try {
      const { readGainLog } = requireSourceOrBundled('./src/tracking/logger');
      const { aggregate } = requireSourceOrBundled('./src/tracking/aggregate');
      const { renderSummary, renderBreakdown } = requireSourceOrBundled('./src/format/gain-terminal');
      const records = readGainLog(cwd);
      const agg = aggregate(records, {
        model: valOf('--model', 'claude-sonnet'),
        since: valOf('--since', null),
        top: parseInt(valOf('--top', args.includes('--all') ? '0' : '10'), 10),
      });
      if (args.includes('--json')) {
        process.stdout.write(JSON.stringify(agg, null, 2) + '\n');
      } else {
        const out = args.includes('--all')
          ? renderSummary(agg, { version: VERSION }) + '\n' + renderBreakdown(agg)
          : renderSummary(agg, { version: VERSION });
        process.stdout.write(out + '\n');
      }
    } catch (e) {
      console.error(`[sigmap] gain: ${e.message}`);
      console.error('  (gain modules require src/ — for single-file installs, regenerate the bundle)');
      process.exit(1);
    }
    process.exit(0);
  }

  // v4.2: `sigmap suggest-profile` — auto-detect task type from git state
  if (args[0] === 'suggest-profile') {
    const short = args.includes('--short');
    let msg = '', diff = '';
    try {
      msg  = __git(['log', '-1', '--format=%s'],        { cwd, timeout: 3000 }).trim();
      diff = __git(['diff', '--cached', '--name-only'], { cwd, timeout: 3000 });
    } catch (_) {}

    let profile = 'default';
    let reason  = 'no strong signal in git state';
    if      (/fix|bug|error|crash|exception/i.test(msg))         { profile = 'debug';        reason = `commit: "${msg.slice(0, 60)}"`;  }
    else if (/refactor|architect|redesign|module/i.test(msg))    { profile = 'architecture'; reason = `commit: "${msg.slice(0, 60)}"`;  }
    else if (/review|pr|pull.request|check/i.test(msg))          { profile = 'review';       reason = `commit: "${msg.slice(0, 60)}"`;  }
    else if (diff.includes('.spec.') || diff.includes('.test.')) { profile = 'debug';        reason = 'staged test files detected'; }

    if (short) {
      console.log(profile);
    } else {
      console.log(`[sigmap] suggested profile: --profile ${profile}`);
      console.log(`  Reason: ${reason}`);
    }
    process.exit(0);
  }

  // v4.2: `sigmap compare` — human-readable benchmark CLI
  if (args[0] === 'compare') {
    const { execFileSync } = require('child_process');
    console.log('[sigmap] Running comparison benchmark (this may take ~30s)...\n');

    let raw = '';
    try {
      // Shell-free: run the node binary directly with the script path as an argv.
      raw = execFileSync(
        process.execPath,
        [path.join(__dirname, 'scripts', 'run-retrieval-benchmark.mjs'), '--compare'],
        { cwd, timeout: 90_000, encoding: 'utf8' }
      );
    } catch (e) { raw = (e && e.stdout) ? e.stdout : ''; }

    let results = null;
    try { results = JSON.parse(raw); } catch (_) {}

    if (!results) {
      console.error('[sigmap] Could not parse benchmark output.');
      console.error('  Run manually: node scripts/run-retrieval-benchmark.mjs --skip-run --json');
      process.exit(1);
    }

    if (args.includes('--json')) {
      process.stdout.write(JSON.stringify(results, null, 2) + '\n');
    } else {
      const pct  = (v) => `${(v * 100).toFixed(1)}%`;
      const lift = (a, b) => (b > 0 ? (a / b).toFixed(1) : '∞');
      const bar  = '─'.repeat(44);
      console.log([
        bar,
        ' SigMap vs Baseline',
        bar,
        ` hit@5         ${pct(results.sigmap.hitAt5)} vs ${pct(results.baseline.hitAt5)}   (${lift(results.sigmap.hitAt5, results.baseline.hitAt5)}× lift)`,
        ` Avg tokens    ${results.sigmap.tokens.toLocaleString()} vs ${results.baseline.tokens.toLocaleString()}`,
        bar,
      ].join('\n'));
    }
    process.exit(0);
  }

  // v4.2: `sigmap share` — shareable one-liner with live benchmark numbers
  if (args[0] === 'share') {
    const histPath = path.join(cwd, '.context', 'benchmark-history.ndjson');
    let reduction = 97, hitAt5 = 88;

    if (fs.existsSync(histPath)) {
      try {
        const entries = fs.readFileSync(histPath, 'utf8').trim().split('\n')
          .map((l) => { try { return JSON.parse(l); } catch (_) { return null; } }).filter(Boolean);
        const tok = [...entries].reverse().find((e) => e.type === 'token-reduction');
        const ret = [...entries].reverse().find((e) => e.type === 'retrieval');
        if (tok && tok.reduction) reduction = tok.reduction;
        if (ret && ret.hitAt5)   hitAt5    = Math.round(ret.hitAt5 * 100);
      } catch (_) {}
    }

    const shareText = [
      'Generated with SigMap — zero-dependency AI context engine',
      `${reduction}% fewer tokens · ${hitAt5}% retrieval accuracy · 6× better results`,
      'https://sigmap.io',
    ].join('\n');

    console.log(shareText);

    try {
      // Shell-free: spawn the clipboard binary directly and write the text to its
      // stdin — no shell, no pipe, no string-built command.
      const { execFileSync } = require('child_process');
      const [clipBin, clipArgs] = process.platform === 'darwin'
        ? ['pbcopy', []]
        : ['xclip', ['-selection', 'clipboard']];
      execFileSync(clipBin, clipArgs, { input: shareText, timeout: 2000 });
      console.log('\n[sigmap] Copied to clipboard.');
    } catch (_) {}

    process.exit(0);
  }

  // v6.8: `sigmap plan "<goal>"` — analyze what files need changes and impact radius
  if (args[0] === 'plan') {
    const goal = args[1];
    if (!goal || goal.startsWith('--')) {
      console.error('[sigmap] Usage: sigmap plan "<goal>"');
      console.error('  Example: sigmap plan "add rate limiting to the API"');
      process.exit(1);
    }

    const { detectIntent, buildSigIndex, rank } = requireSourceOrBundled('./src/retrieval/ranker');

    const intent = detectIntent(goal);
    const intentWeights = getIntentWeights(intent);

    const sigIndex = buildSigIndex(cwd);
    if (sigIndex.size === 0) {
      console.error('[sigmap] no context file found. Run: sigmap (to generate first)');
      process.exit(1);
    }

    const ranked = rank(goal, sigIndex, { topK: 15, weights: intentWeights, cwd });

    // Separate into confidence levels
    const highConf = ranked.filter(r => r.confidence === 'high').slice(0, 5);
    const medConf = ranked.filter(r => r.confidence === 'medium').slice(0, 5);

    // Compute impact radius (simplified — no graph for now)
    let impact = null;

    // Identify likely-affected tests (simplified — checks for .test. or .spec. in filename)
    const testedFiles = highConf.filter(r => /\.(test|spec)\.(js|ts|py)$|_test\.(js|ts|py)$/.test(r.file));

    if (args.includes('--json')) {
      process.stdout.write(JSON.stringify({
        goal, intent,
        inspectFirst: highConf.map(r => r.file),
        likelyToChange: medConf.map(r => r.file),
        impactRadius: impact,
        testsAffected: testedFiles.map(r => r.file),
      }, null, 2) + '\n');
    } else {
      const bar = '─'.repeat(50);
      console.log(bar);
      console.log(` sigmap plan  "${goal}"`);
      console.log(` Intent     : ${intent}`);
      console.log(bar);
      console.log('');
      console.log(' Inspect first (highest relevance):');
      if (highConf.length === 0) {
        console.log('   (no files found)');
      } else {
        highConf.forEach((r, i) => console.log(`   ${i + 1}. ${path.relative(cwd, r.file)}`));
      }
      console.log('');
      console.log(' Likely to change:');
      if (medConf.length === 0) {
        console.log('   (no files found)');
      } else {
        medConf.forEach((r, i) => console.log(`   ${i + 1}. ${path.relative(cwd, r.file)}`));
      }
      if (testedFiles.length > 0) {
        console.log('');
        console.log(' Tests to run after change:');
        testedFiles.forEach(r => console.log(`   • ${path.relative(cwd, r.file)}`));
      }
      console.log('');
      console.log(bar);
    }
    process.exit(0);
  }

  // v5.9: `sigmap bench --submit` — format local benchmark history as a shareable community block
  if (args[0] === 'bench' && args.includes('--submit')) {
    const versionMeta = (() => {
      try { return JSON.parse(fs.readFileSync(path.join(__dirname, 'version.json'), 'utf8')); }
      catch (_) { return {}; }
    })();

    const histPath = path.join(cwd, '.context', 'benchmark-history.ndjson');
    let localMetrics = null;
    if (fs.existsSync(histPath)) {
      try {
        const entries = fs.readFileSync(histPath, 'utf8').trim().split('\n')
          .map((l) => { try { return JSON.parse(l); } catch (_) { return null; } }).filter(Boolean);
        const ret = [...entries].reverse().find((e) => e.type === 'retrieval');
        const tok = [...entries].reverse().find((e) => e.type === 'token-reduction');
        if (ret || tok) {
          localMetrics = {
            hitAt5Pct:       ret ? (ret.hitAt5Pct || Math.round((ret.hitAt5 || 0) * 100)) : null,
            reductionPct:    tok ? (tok.reduction || tok.avgReductionPct || null) : null,
            runDate:         (ret || tok).ts ? new Date((ret || tok).ts).toISOString().slice(0, 10) : null,
          };
        }
      } catch (_) {}
    }

    const canonical = versionMeta.metrics || {};
    const submission = {
      sigmapVersion:     versionMeta.version || 'unknown',
      benchmarkId:       versionMeta.benchmark_id || 'unknown',
      canonicalHitAt5:   canonical.hit_at_5 != null ? Math.round(canonical.hit_at_5 * 1000) / 10 : null,
      canonicalReduction: canonical.overall_token_reduction_pct || null,
      local:             localMetrics,
      submittedAt:       new Date().toISOString().slice(0, 10),
    };

    if (args.includes('--json')) {
      process.stdout.write(JSON.stringify(submission, null, 2) + '\n');
    } else {
      const bar = '─'.repeat(56);
      const lines = [
        bar,
        ' SigMap Community Benchmark Submission',
        bar,
        ` SigMap version : ${submission.sigmapVersion}`,
        ` Benchmark ID   : ${submission.benchmarkId}`,
        ` Submitted      : ${submission.submittedAt}`,
        bar,
        ' Canonical metrics (official release):',
        ` hit@5          : ${submission.canonicalHitAt5 != null ? submission.canonicalHitAt5 + '%' : 'n/a'}`,
        ` token reduction: ${submission.canonicalReduction != null ? submission.canonicalReduction + '%' : 'n/a'}`,
      ];
      if (localMetrics) {
        lines.push(bar, ' Local run metrics (this repo):');
        if (localMetrics.hitAt5Pct != null)    lines.push(` hit@5          : ${localMetrics.hitAt5Pct}%`);
        if (localMetrics.reductionPct != null)  lines.push(` token reduction: ${localMetrics.reductionPct}%`);
        if (localMetrics.runDate)               lines.push(` run date       : ${localMetrics.runDate}`);
      } else {
        lines.push(bar, ' Local run metrics: none yet — run node scripts/run-retrieval-benchmark.mjs');
      }
      lines.push(bar);
      lines.push(' Paste the block above into a GitHub Discussion to share your results.');
      lines.push(' https://github.com/manojmallick/sigmap/discussions');
      lines.push(bar);
      console.log(lines.join('\n'));
    }
    process.exit(0);
  }

  // v5.2: `sigmap learn` — manual learning controls for ranking
  if (args[0] === 'learn') {
    const doReset = args.includes('--reset');
    const good = collectLearnFiles(args, '--good', cwd);
    const bad = collectLearnFiles(args, '--bad', cwd);

    if (doReset && (good.rawCount > 0 || bad.rawCount > 0)) {
      console.error('[sigmap] --reset cannot be combined with --good or --bad');
      process.exit(1);
    }

    if (doReset) {
      const { resetWeights } = requireSourceOrBundled('./src/learning/weights');
      resetWeights(cwd);
      console.log('[sigmap] weights reset — all files back to baseline');
      process.exit(0);
    }

    if (good.rawCount === 0 && bad.rawCount === 0) {
      console.error('[sigmap] Usage: sigmap learn --good <files...> [--bad <files...>] | sigmap learn --reset');
      process.exit(1);
    }

    for (const warning of [...good.warnings, ...bad.warnings]) {
      console.warn(`[sigmap] warning: ${warning}`);
    }

    if (good.files.length === 0 && bad.files.length === 0) {
      console.error('[sigmap] No valid files to learn from.');
      process.exit(1);
    }

    const { updateWeights } = requireSourceOrBundled('./src/learning/weights');
    const result = updateWeights(cwd, { goodFiles: good.files, badFiles: bad.files });
    const parts = [];
    if (result.good.length) parts.push(`boosted ${result.good.length} file(s)`);
    if (result.bad.length) parts.push(`penalized ${result.bad.length} file(s)`);
    console.log(`[sigmap] learned: ${parts.join(', ')}`);
    process.exit(0);
  }

  // v5.2: `sigmap weights` — explain learned ranking multipliers
  if (args[0] === 'weights') {
    const { loadWeights, exportWeights, importWeights } = requireSourceOrBundled('./src/learning/weights');

    if (args.includes('--export')) {
      const exportIdx = args.indexOf('--export');
      const maybeFile = args[exportIdx + 1];
      const exportFile = (maybeFile && !maybeFile.startsWith('--')) ? maybeFile : null;
      exportWeights(cwd, exportFile);
      if (exportFile) console.warn(`[sigmap] weights exported to ${exportFile}`);
      process.exit(0);
    }

    if (args.includes('--import')) {
      const importIdx = args.indexOf('--import');
      const importFile = args[importIdx + 1];
      if (!importFile || importFile.startsWith('--')) {
        console.error('[sigmap] --import requires a file path');
        process.exit(1);
      }
      const replace = args.includes('--replace');
      try {
        const result = importWeights(cwd, importFile, replace);
        const count = Object.keys(result).length;
        console.warn(`[sigmap] weights ${replace ? 'replaced' : 'merged'} from ${importFile} — ${count} file(s) with non-baseline weights`);
      } catch (err) {
        console.error(`[sigmap] weights import failed: ${err.message}`);
        process.exit(1);
      }
      process.exit(0);
    }

    const weights = loadWeights(cwd);
    const entries = Object.entries(weights).sort(([, a], [, b]) => b - a || 0);

    if (args.includes('--json')) {
      process.stdout.write(JSON.stringify(weights, null, 2) + '\n');
      process.exit(0);
    }

    if (entries.length === 0) {
      console.log('[sigmap] No learned weights yet. Run: sigmap learn --good <file>');
      process.exit(0);
    }

    console.log('[sigmap] Learned file weights (xmultiplier vs baseline):');
    for (const [file, mult] of entries) {
      const bar = mult >= 1
        ? `+${'█'.repeat(Math.max(1, Math.round((mult - 1) * 10)))}`
        : `-${'░'.repeat(Math.max(1, Math.round((1 - mult) * 10)))}`;
      console.log(`  ${file.padEnd(50)} x${mult.toFixed(2)}  ${bar}`);
    }
    console.log(`\n  Total files with learned weights: ${entries.length}`);
    console.log('  To reset: sigmap learn --reset');
    process.exit(0);
  }

  // v4.3: `sigmap validate` — config + coverage + optional query symbol check
  if (args[0] === 'validate') {
    const issues   = [];
    const warnings = [];

    // Config checks
    for (const d of (config.srcDirs || [])) {
      if (!fs.existsSync(path.join(cwd, d)))
        issues.push(`srcDir '${d}' does not exist`);
    }
    if ((config.exclude || []).some((p) => p === 'src/**'))
      issues.push(`exclude pattern 'src/**' will exclude all source files`);
    if ((config.maxTokens || 0) < 1000)
      warnings.push(`maxTokens ${config.maxTokens} is very low — consider ≥ 4000`);
    if ((config.maxTokens || 0) > 50000)
      warnings.push(`maxTokens ${config.maxTokens} is very high — may exceed LLM context windows`);

    // Coverage check: files actually in context vs total source files
    const { buildSigIndex: valBuildSigIndex } = requireSourceOrBundled('./src/retrieval/ranker');
    const valSigIndex  = valBuildSigIndex(cwd);
    const valTotal     = buildFileList(cwd, config).length;
    const coveragePct  = valTotal > 0 ? Math.round((valSigIndex.size / valTotal) * 100) : 0;
    if (coveragePct < 70)
      warnings.push(`coverage ${coveragePct}% is below recommended 70% — increase maxTokens or expand srcDirs`);

    // Optional query symbol check
    const valQueryIdx = args.indexOf('--query');
    if (valQueryIdx !== -1) {
      const q = (args[valQueryIdx + 1] || '').trim();
      if (q && !q.startsWith('--')) {
        try {
          const { rank, buildSigIndex } = requireSourceOrBundled('./src/retrieval/ranker');
          const ranked = rank(q, buildSigIndex(cwd), { topK: 5, cwd });
          const symbols = extractQuerySymbols(q);
          const missing = symbols.filter((sym) =>
            !ranked.some((r) => r.sigs && r.sigs.some((s) => s.toLowerCase().includes(sym.toLowerCase())))
          );
          if (missing.length > 0)
            warnings.push(`query "${q}" references symbols not in top-5 context: ${missing.join(', ')}`);
          else if (symbols.length > 0)
            console.log(`[sigmap] ✓ query coverage OK — all ${symbols.length} symbols found`);
        } catch (_) {}
      }
    }

    if (args.includes('--json')) {
      process.stdout.write(JSON.stringify({ valid: issues.length === 0, issues, warnings, coverage: coveragePct }) + '\n');
    } else {
      for (const w of warnings) console.warn(`[sigmap] ⚠  ${w}`);
      if (issues.length === 0) {
        console.log(`[sigmap] ✓ config valid  coverage: ${coveragePct}%`);
      } else {
        for (const iss of issues) console.error(`[sigmap] ✗ ${iss}`);
        process.exit(1);
      }
    }
    process.exit(0);
  }

  // v5.0: `sigmap judge --response <file> --context <file>` — groundedness scoring
  if (args[0] === 'judge') {
    const respIdx = args.indexOf('--response');
    const ctxIdx  = args.indexOf('--context');

    if (respIdx < 0 || ctxIdx < 0) {
      console.error('[sigmap] Usage: sigmap judge --response <file> --context <file> [--json] [--threshold 0.25] [--learn]');
      process.exit(1);
    }

    const respFile = (args[respIdx + 1] || '').trim();
    const ctxFile  = (args[ctxIdx + 1]  || '').trim();

    if (!respFile || respFile.startsWith('--') || !ctxFile || ctxFile.startsWith('--')) {
      console.error('[sigmap] --response and --context require file paths');
      process.exit(1);
    }

    let responseText = '', contextText = '';
    try { responseText = fs.readFileSync(path.resolve(cwd, respFile), 'utf8'); }
    catch (e) { console.error(`[sigmap] cannot read --response file: ${e.message}`); process.exit(1); }
    try { contextText = fs.readFileSync(path.resolve(cwd, ctxFile), 'utf8'); }
    catch (e) { console.error(`[sigmap] cannot read --context file: ${e.message}`); process.exit(1); }

    const thrIdx = args.indexOf('--threshold');
    const judgeOpts = thrIdx >= 0 ? { threshold: parseFloat(args[thrIdx + 1]) || 0.25 } : {};
    if (args.includes('--learn')) {
      judgeOpts.learn = true;
      judgeOpts.cwd = cwd;
    }

    const { judge: runJudge } = requireSourceOrBundled('./src/judge/judge-engine');
    const result = runJudge(responseText, contextText, judgeOpts);

    if (args.includes('--json')) {
      process.stdout.write(JSON.stringify(result) + '\n');
    } else {
      const bar = '─'.repeat(44);
      console.log([
        bar,
        ` sigmap judge`,
        ` Score     : ${result.score}`,
        ` Verdict   : ${result.verdict}`,
        result.reasons.length ? ` Reasons   :\n   ${result.reasons.join('\n   ')}` : ` Reasons   : none`,
        result.learning
          ? ` Learning  : ${result.learning.applied ? result.learning.action : 'skipped'}${result.learning.files.length ? ` (${result.learning.files.join(', ')})` : ''}${result.learning.reason ? ` — ${result.learning.reason}` : ''}`
          : null,
        bar,
      ].filter(Boolean).join('\n'));
    }
    process.exit(result.verdict === 'pass' ? 0 : 1);
  }

  // v5.0: `sigmap history` — show last N usage log entries with sparkline
  if (args[0] === 'history') {
    const { readLog } = requireSourceOrBundled('./src/tracking/logger');
    const entries = readLog(cwd);

    const nIdx = args.indexOf('--last');
    const n    = nIdx >= 0 ? (parseInt(args[nIdx + 1], 10) || 10) : 10;
    const last = entries.slice(-n);

    if (args.includes('--json')) {
      process.stdout.write(JSON.stringify(last) + '\n');
      process.exit(0);
    }

    const SPARK_CHARS = '▁▂▃▄▅▆▇█';
    function sparkline(values) {
      if (values.length === 0) return '';
      const min = Math.min(...values);
      const max = Math.max(...values);
      const range = max - min || 1;
      return values.map((v) => {
        const idx = Math.round(((v - min) / range) * (SPARK_CHARS.length - 1));
        return SPARK_CHARS[idx];
      }).join('');
    }

    const bar = '─'.repeat(62);
    console.log(bar);
    console.log(` sigmap history  (last ${Math.max(last.length, 1)} runs)`);
    console.log(bar);

    if (last.length === 0) {
      console.log(' No usage log entries. Enable tracking: true in config to start recording runs.');
    } else {
      console.log(` ${'Date'.padEnd(24)} ${'Files'.padStart(5)} ${'Tokens'.padStart(7)} ${'Reduction'.padStart(9)} ${'Budget?'.padStart(7)}`);
      console.log(` ${'─'.repeat(24)} ${'─'.repeat(5)} ${'─'.repeat(7)} ${'─'.repeat(9)} ${'─'.repeat(7)}`);
      for (const e of last) {
        const date = (e.ts || '').slice(0, 19).replace('T', ' ');
        const files = String(e.fileCount || 0).padStart(5);
        const tok   = String(e.finalTokens || 0).padStart(7);
        const red   = `${e.reductionPct || 0}%`.padStart(9);
        const over  = (e.overBudget ? '  ⚠ yes' : '     no').padStart(7);
        console.log(` ${date.padEnd(24)} ${files} ${tok} ${red} ${over}`);
      }
      console.log(bar);
      const tokens = last.map((e) => e.finalTokens || 0);
      console.log(` Token trend: ${sparkline(tokens)}`);
    }

    // Show benchmark trend row if .context/benchmark-history.ndjson exists
    const benchHistPath = path.join(cwd, '.context', 'benchmark-history.ndjson');
    if (fs.existsSync(benchHistPath)) {
      try {
        const benchEntries = fs.readFileSync(benchHistPath, 'utf8').trim().split('\n')
          .map((l) => { try { return JSON.parse(l); } catch (_) { return null; } }).filter(Boolean);
        const retrieval = benchEntries.filter((e) => e.type === 'retrieval').slice(-n);
        if (retrieval.length > 0) {
          const hits = retrieval.map((e) => e.hitAt5Pct || 0);
          console.log(` hit@5 trend: ${sparkline(hits)}  ${hits.at(-1)}% (latest)`);
        }
        const tokenBench = benchEntries.filter((e) => e.type === 'token-reduction').slice(-n);
        if (tokenBench.length > 0) {
          const reds = tokenBench.map((e) => e.reduction || e.avgReductionPct || 0);
          console.log(` tok reduce : ${sparkline(reds)}  ${reds.at(-1)}% (latest)`);
        }
      } catch (_) {}
    }

    console.log(bar);
    process.exit(0);
  }

  // Feature 6: `sigmap sync` — write all outputs + llms.txt + print compact diff
  if (args[0] === 'sync') {
    try {
      // Generate copilot-instructions.md first (existing output)
      runGenerate(cwd, config, false);
      const llmTxt = requireSourceOrBundled('./src/format/llm-txt');
      const llmsGen = requireSourceOrBundled('./src/format/llms-txt');
      const llmFullMod = requireSourceOrBundled('./packages/adapters/llm-full');

      // Gather file entries for llm.txt / llm-full.txt
      const ignorePatterns = loadIgnorePatterns(cwd);
      let syncFiles = buildFileList(cwd, config).filter((f) => {
        const rel = path.relative(cwd, f).replace(/\\/g, '/');
        return !matchesIgnore(rel, ignorePatterns);
      });
      const syncEntries = [];
      for (const fp of syncFiles) {
        let content = '';
        try { content = fs.readFileSync(fp, 'utf8'); } catch (_) { continue; }
        const sigs = detectAndExtract(fp, content, config.maxSigsPerFile || 25);
        if (sigs.length === 0) continue;
        syncEntries.push({ filePath: fp, sigs, language: null });
      }
      const syncContext = {
        projectName: path.basename(cwd),
        fileEntries: syncEntries,
        srcDirs: config.srcDirs || [],
      };

      const llmTxtPath   = llmTxt.outputPath(cwd);
      const llmFullPath  = llmFullMod.outputPath(cwd);
      const llmsTxtPath  = llmsGen.outputPath(cwd);

      fs.writeFileSync(llmTxtPath,  llmTxt.format(syncContext, cwd, VERSION));
      llmFullMod.write(syncContext, cwd, { version: VERSION });

      const prev  = fs.existsSync(llmsTxtPath) ? fs.readFileSync(llmsTxtPath, 'utf8') : '';
      const next  = llmsGen.format(syncContext, cwd, [
        { path: llmTxtPath,  label: 'llm.txt' },
        { path: llmFullPath, label: 'llm-full.txt' },
      ], VERSION);
      const changed = prev !== next ? 'updated' : 'no change';
      fs.writeFileSync(llmsTxtPath, next);

      console.log('[sigmap] sync complete');
      console.log(`  .github/copilot-instructions.md  updated`);
      console.log(`  llm.txt                          updated`);
      console.log(`  llm-full.txt                     updated`);
      console.log(`  llms.txt                         ${changed}`);
    } catch (err) {
      console.error(`[sigmap] sync error: ${err.message}`);
      process.exit(1);
    }
    process.exit(0);
  }

  // v6.5: `sigmap roots` — detect source roots
  if (args[0] === 'roots') {
    const { resolveSourceRoots } = requireSourceOrBundled('./src/discovery/source-root-resolver');
    const result = resolveSourceRoots(cwd);

    if (args.includes('--json')) {
      console.log(JSON.stringify(result, null, 2));
      process.exit(0);
    }

    if (args.includes('--fix')) {
      console.log('[sigmap] Current detected roots:', result.roots.join(', '));
      const readline = require('readline');
      const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
      rl.question('Enter correct srcDirs (comma-separated): ', answer => {
        const dirs = answer.split(',').map(d => d.trim()).filter(Boolean);
        const cfgPath = path.join(cwd, 'gen-context.config.json');
        const cfg = fs.existsSync(cfgPath) ? JSON.parse(fs.readFileSync(cfgPath, 'utf8')) : {};
        cfg.srcDirs = dirs;
        fs.writeFileSync(cfgPath, JSON.stringify(cfg, null, 2) + '\n');
        console.log(`[sigmap] Saved srcDirs: ${dirs.join(', ')} → gen-context.config.json`);
        rl.close();
        process.exit(0);
      });
      return;
    }

    // --explain (default)
    console.log('\nDetected languages:');
    for (const l of result.languages.slice(0, 4)) {
      console.log(`  ${l.name.padEnd(16)} ${l.weight.toFixed(2)}`);
    }
    console.log('\nDetected frameworks:');
    if (result.frameworks.length === 0) console.log('  (none)');
    for (const f of result.frameworks.slice(0, 3)) {
      console.log(`  ${f.name.padEnd(16)} ${f.confidence.toFixed(2)}`);
    }
    console.log('\nChosen source roots:');
    if (result.roots.length === 0) console.log('  (none — legacy fallback used)');
    result.roots.forEach((r, i) => {
      const exp = result.explanation?.find(e => e.dir === r);
      console.log(`  ${i + 1}. ${r.padEnd(20)} ${exp ? 'score ' + exp.score : ''}`);
    });
    console.log('\nMonorepo:', result.isMonorepo ? 'yes' : 'no');
    console.log('Confidence:', result.confidence);
    process.exit(0);
  }

  // `sigmap note "<text>"` — append to the cross-session decision log.
  // With no text, lists recent notes (also `note --list [N]`).
  if (args[0] === 'note') {
    const jsonOut = args.includes('--json');
    const { addNote, readNotes, formatNotes } = requireSourceOrBundled('./src/session/notes');
    const listIdx = args.indexOf('--list');
    // Build positionals, skipping value-taking flags and their values
    // (e.g. `--cwd <dir>`, `--list <N>`) so they never leak into the note text.
    const VALUE_FLAGS = new Set(['--cwd', '--list']);
    const positional = [];
    for (let i = 1; i < args.length; i++) {
      const a = args[i];
      if (a.startsWith('--')) { if (VALUE_FLAGS.has(a)) i++; continue; }
      positional.push(a);
    }
    const wantsList = listIdx !== -1 || positional.length === 0;

    if (wantsList) {
      const limArg = listIdx !== -1 ? parseInt(args[listIdx + 1], 10) : parseInt(positional[0], 10);
      const limit = Number.isFinite(limArg) && limArg > 0 ? limArg : 10;
      const notes = readNotes(cwd, limit);
      if (jsonOut) {
        process.stdout.write(JSON.stringify({ notes }) + '\n');
      } else {
        console.log(`[sigmap] ${notes.length} recent note${notes.length === 1 ? '' : 's'}`);
        console.log(formatNotes(notes.slice().reverse()));
      }
      process.exit(0);
    }

    const text = positional.join(' ');
    let entry;
    try {
      entry = addNote(cwd, text);
    } catch (err) {
      console.error(`[sigmap] ${err.message}`);
      process.exit(1);
    }
    if (jsonOut) {
      process.stdout.write(JSON.stringify({ added: entry }) + '\n');
    } else {
      console.log(`[sigmap] noted${entry.branch ? ` (${entry.branch})` : ''}: ${entry.text}`);
    }
    process.exit(0);
  }

  // `sigmap status` — environment / repo state at a glance.
  if (args[0] === 'status') {
    const jsonOut = args.includes('--json');
    const gitOpts = { cwd };
    const st = { branch: null, dirty: 0, lastIndex: null, indexVersion: null, indexFiles: null, changedSinceIndex: null, notes: 0, lastNote: null };

    st.branch = __tryGit(['rev-parse', '--abbrev-ref', 'HEAD'], gitOpts) || null;
    // Fallback for an unborn branch (fresh repo, no commits yet).
    if (!st.branch || st.branch === 'HEAD') {
      st.branch = __tryGit(['symbolic-ref', '--short', 'HEAD'], gitOpts) || st.branch;
    }
    try {
      const porcelain = __git(['status', '--porcelain'], gitOpts).trim();
      st.dirty = porcelain ? porcelain.split('\n').filter(Boolean).length : 0;
    } catch (_) {}

    try {
      const { readLog } = requireSourceOrBundled('./src/tracking/logger');
      const log = readLog(cwd);
      if (log.length) {
        const last = log[log.length - 1];
        st.lastIndex = last.ts || null;
        st.indexVersion = last.version || null;
        st.indexFiles = last.fileCount != null ? last.fileCount : null;
      }
    } catch (_) {}

    // Index freshness: count tracked files modified after the last index run.
    if (st.lastIndex) {
      try {
        const since = Date.parse(st.lastIndex);
        const tracked = __git(['ls-files'], gitOpts).split('\n').filter(Boolean);
        let changed = 0;
        for (const f of tracked.slice(0, 5000)) {
          try { if (fs.statSync(path.join(cwd, f)).mtimeMs > since) changed++; } catch (_) {}
        }
        st.changedSinceIndex = changed;
      } catch (_) {}
    }

    try {
      const { readNotes } = requireSourceOrBundled('./src/session/notes');
      const notes = readNotes(cwd);
      st.notes = notes.length;
      if (notes.length) st.lastNote = notes[notes.length - 1];
    } catch (_) {}

    if (jsonOut) {
      process.stdout.write(JSON.stringify(st) + '\n');
      process.exit(0);
    }

    const fmtAgo = (iso) => {
      if (!iso) return 'never';
      const ms = Date.now() - Date.parse(iso);
      if (!Number.isFinite(ms)) return iso;
      const m = Math.floor(ms / 60000), h = Math.floor(m / 60), d = Math.floor(h / 24);
      if (d > 0) return `${d}d ago`;
      if (h > 0) return `${h}h ago`;
      if (m > 0) return `${m}m ago`;
      return 'just now';
    };

    console.log('[sigmap] status');
    console.log(`  Branch:        ${st.branch || '(not a git repo)'}`);
    console.log(`  Working tree:  ${st.dirty === 0 ? 'clean' : `${st.dirty} file${st.dirty === 1 ? '' : 's'} changed`}`);
    if (st.lastIndex) {
      let fresh = `${fmtAgo(st.lastIndex)} (v${st.indexVersion || '?'}, ${st.indexFiles != null ? st.indexFiles + ' files' : 'n/a'})`;
      if (st.changedSinceIndex != null && st.changedSinceIndex > 0) fresh += ` — STALE: ${st.changedSinceIndex} file${st.changedSinceIndex === 1 ? '' : 's'} changed since`;
      console.log(`  Last index:    ${fresh}`);
    } else {
      console.log('  Last index:    never — run: sigmap');
    }
    if (st.notes > 0) {
      console.log(`  Notes:         ${st.notes} (latest: ${st.lastNote.text.slice(0, 60)}${st.lastNote.text.length > 60 ? '…' : ''})`);
    } else {
      console.log('  Notes:         none — add with: sigmap note "<text>"');
    }
    process.exit(0);
  }

  // Layer 3: `sigmap conventions` — extract & report repo coding conventions
  // (file naming, export style, test framework) for TS/JS/Python so generated
  // code matches the house style. Writes .context/conventions.json.
  if (args[0] === 'conventions') {
    const jsonOut = args.includes('--json');
    const { extractConventions } = requireSourceOrBundled('./src/conventions/extract');
    const files = buildFileList(cwd, config);
    const result = extractConventions(cwd, files);

    // `--inject`: write/update the conventions block in CLAUDE.md (idempotent).
    if (args.includes('--inject')) {
      const { renderConventionsBlock, injectConventions } = requireSourceOrBundled('./src/conventions/inject');
      const claudePath = path.join(cwd, 'CLAUDE.md');
      let existing = '';
      try { if (fs.existsSync(claudePath)) existing = fs.readFileSync(claudePath, 'utf8'); } catch (_) {}
      const block = renderConventionsBlock(result, VERSION);
      try {
        fs.writeFileSync(claudePath, injectConventions(existing, block));
      } catch (e) {
        console.error(`[sigmap] cannot write ${claudePath}: ${e.message}`);
        process.exit(1);
      }
      console.log(`[sigmap] conventions → injected block into ${path.relative(cwd, claudePath) || 'CLAUDE.md'}`);
      process.exit(0);
    }

    // `--conflicts`: surface why a convention is mixed (breakdown + rename suggestions).
    if (args.includes('--conflicts')) {
      const { analyzeConflicts } = requireSourceOrBundled('./src/conventions/conflicts');
      const report = analyzeConflicts(result);
      if (jsonOut) {
        process.stdout.write(JSON.stringify(report) + '\n');
        process.exit(0);
      }
      const pctC = (n) => `${(n * 100).toFixed(0)}%`;
      if (!report.hasConflicts) {
        console.log('[sigmap] conventions --conflicts  (TS/JS/Python)');
        console.log('  no conflicts — conventions are consistent ✓');
        process.exit(0);
      }
      console.log('[sigmap] conventions --conflicts  (TS/JS/Python)');
      for (const c of report.conventions) {
        console.log(`\n  ${c.name} — dominant: ${c.dominant} ${pctC(c.dominantPct)} [${c.tier}]`);
        for (const v of c.variants) {
          const barLen = Math.max(1, Math.round(v.pct * 20));
          const bar = '█'.repeat(barLen);
          const tag = v.pattern === c.dominant ? ' (dominant)' : '';
          const ex = v.examples.length ? `  e.g. ${v.examples.join(', ')}` : '';
          console.log(`    ${v.pattern.padEnd(12)} ${String(v.count).padStart(4)}  ${pctC(v.pct).padStart(4)} ${bar}${tag}${ex}`);
        }
        if (c.renames.length) {
          console.log(`    rename to match ${c.dominant}:`);
          for (const r of c.renames) console.log(`      ${r.from}  →  ${r.to}`);
        }
      }
      process.exit(0);
    }

    const outDir = path.join(cwd, '.context');
    const outPath = path.join(outDir, 'conventions.json');
    try {
      fs.mkdirSync(outDir, { recursive: true });
      fs.writeFileSync(outPath, JSON.stringify(result, null, 2) + '\n');
    } catch (e) {
      console.error(`[sigmap] cannot write ${outPath}: ${e.message}`);
      process.exit(1);
    }

    if (jsonOut) {
      process.stdout.write(JSON.stringify(result) + '\n');
      process.exit(0);
    }

    const pct = (n) => `${(n * 100).toFixed(0)}%`;
    const tierLabel = { consistent: 'consistent', mostly: 'mostly', inconsistent: 'mixed', unknown: 'n/a' };
    const line = (name, conv) => {
      if (!conv || conv.total === 0) return `  ${name.padEnd(14)} n/a (no samples)`;
      const variants = conv.variants.slice(1, 3).map((v) => `${v.label} ${pct(v.pct)}`).join(', ');
      const tail = variants ? `  ·  also: ${variants}` : '';
      return `  ${name.padEnd(14)} ${conv.dominant} ${pct(conv.dominantPct)} [${tierLabel[conv.tier]}]${tail}`;
    };

    console.log('[sigmap] conventions  (TS/JS/Python)');
    console.log(`  scanned        ${result.scannedFiles} file${result.scannedFiles === 1 ? '' : 's'}`);
    console.log(line('file naming', result.fileNaming));
    console.log(line('export style', result.exportStyle));
    console.log(`  ${'test framework'.padEnd(14)} ${result.testFramework || 'none detected'}`);
    console.log(`\n  → wrote ${path.relative(cwd, outPath)}`);
    process.exit(0);
  }

  // Layer 4: `sigmap scaffold <name>` — propose a convention-matched structure
  // for a new module, gated by a confidence floor (refuses if conventions are
  // too inconsistent; a wrong proposal systematizes bad code).
  if (args[0] === 'scaffold') {
    const jsonOut = args.includes('--json');
    const name = args[1] && !args[1].startsWith('--') ? args[1] : null;
    if (!name) {
      console.error('[sigmap] usage: sigmap scaffold <name> [--ext <e>] [--threshold <n>] [--force] [--json]');
      process.exit(1);
    }
    const thIdx = args.indexOf('--threshold');
    const threshold = thIdx !== -1 && args[thIdx + 1] ? parseFloat(args[thIdx + 1]) : undefined;
    const extIdx = args.indexOf('--ext');
    const ext = extIdx !== -1 && args[extIdx + 1] ? args[extIdx + 1].replace(/^\./, '') : undefined;
    const force = args.includes('--force');

    const { extractConventions } = requireSourceOrBundled('./src/conventions/extract');
    const { proposeScaffold } = requireSourceOrBundled('./src/scaffold/propose');
    const conventions = extractConventions(cwd, buildFileList(cwd, config));
    const decision = proposeScaffold(name, conventions, { threshold, ext, force });

    if (jsonOut) {
      process.stdout.write(JSON.stringify(decision) + '\n');
      process.exit(decision.ok ? 0 : 1);
    }

    const pctS = (n) => `${(n * 100).toFixed(0)}%`;
    if (decision.ok) {
      console.log(`[sigmap] scaffold "${decision.name}"  — conventions ${decision.tier} (${pctS(decision.confidence)})`);
      if (decision.warning) console.log(`  ⚠ ${decision.warning}`);
      const p = decision.proposal;
      console.log(`  file:           ${p.filename}  (${p.namingStyle})`);
      console.log(`  export style:   ${p.exportStyle}`);
      console.log(`  test file:      ${p.testFile}${p.testFramework ? `  (${p.testFramework})` : ''}`);
      process.exit(0);
    }

    console.log(`[sigmap] scaffold "${decision.name}" — REFUSED`);
    console.log(`  ${decision.reason}`);
    if (decision.conflicts && decision.conflicts.hasConflicts) {
      for (const c of decision.conflicts.conventions) {
        console.log(`\n  ${c.name} — dominant: ${c.dominant} ${pctS(c.dominantPct)} [${c.tier}]`);
        for (const v of c.variants) {
          console.log(`    ${v.pattern.padEnd(12)} ${pctS(v.pct).padStart(4)}${v.examples.length ? `  e.g. ${v.examples.join(', ')}` : ''}`);
        }
      }
    }
    process.exit(1);
  }

  // v7.0.0: `sigmap squeeze <file|->` — minimize a pasted stacktrace / CI-log / JSON blob
  if (args[0] === 'squeeze') {
    const jsonOut = args.includes('--json');
    const target = args[1] && !args[1].startsWith('--') ? args[1] : '-';
    let input = '';
    try {
      input = fs.readFileSync(target === '-' ? 0 : path.resolve(cwd, target), 'utf8');
    } catch (e) {
      console.error(`[sigmap] cannot read input: ${e.message}`);
      process.exit(1);
    }

    const { squeeze: runSqueeze, formatSummary } = requireSourceOrBundled('./src/squeeze/index');
    let symbolIndex = null;
    try {
      const { buildSigIndex } = requireSourceOrBundled('./src/retrieval/ranker');
      symbolIndex = buildSigIndex(cwd);
    } catch (_) {}
    const sq = runSqueeze(input, { srcDirs: config.srcDirs, symbolIndex });

    try {
      const { checkStarNudge } = requireSourceOrBundled('./src/nudge');
      checkStarNudge(cwd, true, { silent: !process.stderr.isTTY || jsonOut, bump: { squeezeOffered: sq.applies ? 1 : 0 } });
    } catch (_) {}

    if (jsonOut) {
      process.stdout.write(JSON.stringify({
        category: sq.category, confidence: sq.confidence,
        rawTokens: sq.rawTokens, squeezedTokens: sq.squeezedTokens,
        reduction: sq.reduction, enriched: sq.enriched, squeezed: sq.squeezed,
      }) + '\n');
      process.exit(0);
    }
    if (!sq.category) {
      process.stderr.write('[sigmap] no squeezable structure detected — input unchanged\n');
      process.stdout.write(input);
      process.exit(0);
    }
    process.stderr.write(formatSummary(sq) + '\n\n');
    process.stdout.write(sq.squeezed + '\n');
    process.exit(0);
  }

  // `sigmap verify-ai-output <answer.md>` — Hallucination Guard (deterministic core)
  // Gap 2 (step 2): `sigmap verify-plan <plan.md>` — check a plan against the
  // live index before execution (files/symbols exist, blast radius, scope).
  if (args[0] === 'verify-plan') {
    const target = args[1] && !args[1].startsWith('--') ? args[1] : null;
    const jsonOut = args.includes('--json');
    if (!target) {
      console.error('[sigmap] Usage: sigmap verify-plan <plan.md|-> [--json]');
      process.exit(1);
    }
    let planText = '';
    try {
      planText = fs.readFileSync(target === '-' ? 0 : path.resolve(cwd, target), 'utf8');
    } catch (e) {
      console.error(`[sigmap] cannot read plan: ${e.message}`);
      process.exit(1);
    }
    const { verifyPlan } = requireSourceOrBundled('./src/plan/verify-plan');
    const result = verifyPlan(planText, cwd);

    if (jsonOut) {
      process.stdout.write(JSON.stringify(result) + '\n');
      process.exit(result.summary.ok ? 0 : 1);
    }

    const s = result.summary;
    console.log(`[sigmap] verify-plan — ${s.filesReferenced} file(s), ${s.symbolsReferenced} symbol(s) referenced`);
    if (result.issues.length === 0) {
      console.log('  ✓ plan checks out — all references exist, blast radius and scope in bounds');
      process.exit(0);
    }
    for (const i of result.issues) {
      const mark = i.severity === 'error' ? '✗' : '⚠';
      if (i.type === 'missing-file') console.log(`  ${mark} missing file: ${i.ref} (line ${i.line})`);
      else if (i.type === 'unknown-symbol') console.log(`  ${mark} unknown symbol: ${i.ref}()${i.suggestion ? ` — did you mean ${i.suggestion}()?` : ''} (line ${i.line})`);
      else if (i.type === 'high-blast-radius') console.log(`  ${mark} high blast radius: ${i.ref} → ${i.count} dependents`);
      else if (i.type === 'broad-scope') console.log(`  ${mark} broad scope: ${i.count} files (threshold ${i.threshold})`);
    }
    console.log(`\n  ${s.errors} error(s), ${s.warnings} warning(s)`);
    process.exit(s.ok ? 0 : 1);
  }

  if (args[0] === 'verify-ai-output') {
    const target = args[1];
    const jsonOut = args.includes('--json');
    const reportIdx = args.indexOf('--report');
    const reportOut = reportIdx !== -1
      ? (args[reportIdx + 1] && !args[reportIdx + 1].startsWith('--') ? args[reportIdx + 1] : 'sigmap-verify-report.html')
      : null;
    if (!target || target.startsWith('--')) {
      console.error('[sigmap] Usage: sigmap verify-ai-output <answer.md> [--json] [--report [out.html]]');
      process.exit(1);
    }
    const absTarget = path.resolve(cwd, target);
    if (!fs.existsSync(absTarget)) {
      console.error(`[sigmap] file not found: ${target}`);
      process.exit(1);
    }

    const answerText = fs.readFileSync(absTarget, 'utf8');
    const { verify } = requireSourceOrBundled('./src/verify/hallucination-guard');
    const { issues, summary } = verify(answerText, cwd);
    const rel = path.relative(cwd, absTarget) || target;
    const result = { file: rel, issues, summary };

    // Optional HTML report (Surface A) — written alongside any other output.
    if (reportOut) {
      const { renderReportHtml } = requireSourceOrBundled('./src/format/verify-report');
      const outAbs = path.resolve(cwd, reportOut);
      fs.writeFileSync(outAbs, renderReportHtml(result));
      if (!jsonOut) console.log(`[sigmap] report written: ${path.relative(cwd, outAbs) || reportOut}`);
    }

    if (jsonOut) {
      process.stdout.write(JSON.stringify(result) + '\n');
      process.exit(summary.total > 0 ? 1 : 0);
    }

    if (summary.total === 0) {
      console.log(`[sigmap] ✓ ${rel} — no hallucinations detected (${summary.symbolsIndexed} symbols indexed)`);
      process.exit(0);
    }

    const labels = {
      'fake-file': 'Fake file', 'fake-test-file': 'Fake test file',
      'fake-import': 'Fake import', 'fake-symbol': 'Fake symbol',
      'fake-npm-script': 'Fake npm script',
    };
    const bt = summary.byType;
    console.log(`[sigmap] ✗ ${rel} — ${summary.total} issue${summary.total === 1 ? '' : 's'} found`);
    console.log(`  fake-file: ${bt['fake-file']}  fake-test-file: ${bt['fake-test-file']}  fake-import: ${bt['fake-import']}  fake-symbol: ${bt['fake-symbol']}  fake-npm-script: ${bt['fake-npm-script']}`);
    console.log('');
    for (const issue of issues) {
      console.log(`  L${issue.line}  [${labels[issue.type] || issue.type}]  ${issue.message}`);
      if (issue.suggestion) console.log(`         ↳ ${issue.suggestion}`);
    }
    process.exit(1);
  }

  // Feature 1: `sigmap explain <file>` — why a file is included or excluded
  if (args[0] === 'explain' || args.includes('--explain')) {
    const target = args[0] === 'explain'
      ? args[1]
      : args[args.indexOf('--explain') + 1];

    if (!target || target.startsWith('--')) {
      console.error('[sigmap] Usage: sigmap explain <file>');
      process.exit(1);
    }

    const absPath = path.resolve(cwd, target);
    const rel     = path.relative(cwd, absPath);
    const jsonOut = args.includes('--json');

    // 1. Check .contextignore
    const ignorePatterns = loadIgnorePatterns(cwd);
    const ignored = matchesIgnore(rel.replace(/\\/g, '/'), ignorePatterns);
    if (ignored) {
      if (jsonOut) {
        process.stdout.write(JSON.stringify({ status: 'excluded', reason: '.contextignore', fix: `remove the pattern or add '!${rel}' as an exception` }) + '\n');
      } else {
        console.log(`[sigmap] ${rel} — EXCLUDED`);
        console.log(`  Reason: matched .contextignore`);
        console.log(`  Fix:    remove the pattern or add '!${rel}' as an exception`);
      }
      process.exit(0);
    }

    // 2. Check srcDirs membership
    const inSrcDirs = (config.srcDirs || []).some(d => absPath.startsWith(path.resolve(cwd, d)));
    if (!inSrcDirs) {
      if (jsonOut) {
        process.stdout.write(JSON.stringify({ status: 'excluded', reason: 'not in srcDirs', srcDirs: config.srcDirs, fix: 'add the containing directory to srcDirs in gen-context.config.json' }) + '\n');
      } else {
        console.log(`[sigmap] ${rel} — EXCLUDED`);
        console.log(`  Reason: not under any srcDir (${(config.srcDirs || []).join(', ')})`);
        console.log(`  Fix:    add the containing directory to srcDirs in gen-context.config.json`);
      }
      process.exit(0);
    }

    // 3. Detect extractor and extract sigs
    const base    = path.basename(absPath);
    const ext     = path.extname(base).toLowerCase();
    let extractorName = EXT_MAP[ext] || null;
    if (!extractorName && isDockerfile(base)) extractorName = 'dockerfile';
    if (!extractorName) extractorName = 'generic';

    let sigs = [];
    if (fs.existsSync(absPath)) {
      try {
        const content = fs.readFileSync(absPath, 'utf8');
        const extractor = getExtractor(extractorName);
        if (extractor) sigs = extractor.extract(content).slice(0, config.maxSigsPerFile || 25);
      } catch (_) {}
    }

    if (!sigs.length) {
      if (jsonOut) {
        process.stdout.write(JSON.stringify({ status: 'excluded', reason: 'no signatures', extractor: extractorName, fix: 'check that the file contains function/class definitions' }) + '\n');
      } else {
        console.log(`[sigmap] ${rel} — EXCLUDED`);
        console.log(`  Reason: no extractable signatures (extractor: ${extractorName})`);
        console.log(`  Fix:    check that the file contains function/class definitions`);
      }
      process.exit(0);
    }

    // 4. Included
    if (jsonOut) {
      process.stdout.write(JSON.stringify({ status: 'included', extractor: extractorName, signatures: sigs.length, preview: sigs.slice(0, 3), sigs }) + '\n');
    } else {
      console.log(`[sigmap] ${rel} — INCLUDED`);
      console.log(`  Extractor : ${extractorName}`);
      console.log(`  Signatures: ${sigs.length}`);
      console.log(`  Preview   : ${sigs.slice(0, 3).join(' · ')}`);
    }
    process.exit(0);
  }

  if (args.includes('--init')) {
    writeInitConfig(cwd);
    process.exit(0);
  }

  if (args.includes('--health')) {
    const { score } = __require('./src/health/scorer');
    const result = score(cwd);
    // v4.0: compute live coverage score to include in health output
    let coverageResult = null;
    try {
      const { coverageScore } = requireSourceOrBundled('./src/analysis/coverage-score');
      const { loadConfig: lc } = requireSourceOrBundled('./src/config/loader');
      const cfg = lc(cwd);
      // Use all files from srcDirs as proxies for "included" (no budget applied in health mode)
      const allFiles = buildFileList(cwd, cfg);
      const fakeEntries = allFiles.map(f => ({ filePath: f }));
      coverageResult = coverageScore(cwd, fakeEntries, cfg);
    } catch (_) {}
    // v6.7: Collect cache stats if enabled
    let cacheStats = null;
    try {
      const cachePath = path.join(cwd, '.sigmap-cache.json');
      if (fs.existsSync(cachePath)) {
        const raw = fs.readFileSync(cachePath, 'utf8');
        const data = JSON.parse(raw);
        const sizeKb = Math.round(Buffer.byteLength(raw) / 1024);
        const entries = Object.keys(data.entries || {}).length;
        const mtime = fs.statSync(cachePath).mtimeMs;
        cacheStats = { sizeKb, entries, mtimeMs: mtime };
      }
    } catch (_) {}
    if (args.includes('--json')) {
      // Feature 3 (VS Code) + Feature 5 (JetBrains): emit tokens + reduction for plugins
      const ctxPath = path.join(cwd, '.github', 'copilot-instructions.md');
      let tokens = 0;
      let reduction = result.tokenReductionPct || 0;
      if (fs.existsSync(ctxPath)) {
        try { tokens = estimateTokens(fs.readFileSync(ctxPath, 'utf8')); } catch (_) {}
      }
      const payload = { ...result, tokens, reduction };
      if (coverageResult) {
        payload.coverage = coverageResult.score;
        payload.coverageGrade = coverageResult.grade;
        payload.coverageConfidence = coverageResult.confidence;
        payload.coverageTotalFiles = coverageResult.total;
        payload.coverageIncludedFiles = coverageResult.included;
      }
      if (cacheStats) {
        payload.cacheStats = cacheStats;
      }
      process.stdout.write(JSON.stringify(payload) + '\n');
    } else {
      console.log('[sigmap] health:');
      console.log(`  score           : ${result.score}/100 (grade ${result.grade})`);
      if (coverageResult) {
        console.log(`  file access     : ${coverageResult.grade} (${coverageResult.score}%)  — ${coverageResult.included} of ${coverageResult.total} files accessible in srcDirs`);
      }
      console.log(`  strategy        : ${result.strategy}`);
      console.log(`  token reduction : ${result.tokenReductionPct !== null ? result.tokenReductionPct + '%' : 'no history'}`);
      console.log(`  days since regen: ${result.daysSinceRegen !== null ? result.daysSinceRegen : 'context file not found'}`);
      if (result.strategyFreshnessDays !== null) {
        console.log(`  cold freshness  : ${result.strategyFreshnessDays} day(s)`);
      }
      if (cacheStats) {
        console.log(`  sig-cache       : ${cacheStats.entries} files cached  ${cacheStats.sizeKb}KB on disk`);
      }
      console.log(`  total runs      : ${result.totalRuns}`);
      console.log(`  over-budget runs: ${result.overBudgetRuns}`);
      console.log(`  p50 token count : ${result.p50TokenCount}`);
      console.log(`  p95 token count : ${result.p95TokenCount}`);
      console.log(`  overbudget streak: ${result.overBudgetStreak}`);
      console.log(`  repo languages  : ${result.extractorCoverage}% of supported langs used here (informational — not scored)`);
      console.log(`  ${'score basis'.padEnd(16)}: staleness · token reduction · over-budget rate`);
    }
    process.exit(0);
  }

  if (args.includes('--dashboard')) {
    try {
      const { score } = __require('./src/health/scorer');
      const health = score(cwd);
      const { generateDashboardHtml } = requireSourceOrBundled('./src/format/dashboard');
      const out = generateDashboardHtml(cwd, health);
      const outPath = path.join(cwd, 'benchmarks', 'reports', 'dashboard.html');
      fs.mkdirSync(path.dirname(outPath), { recursive: true });
      fs.writeFileSync(outPath, out.html, 'utf8');
      if (args.includes('--json')) {
        process.stdout.write(JSON.stringify({ ok: true, file: path.relative(cwd, outPath), summary: out.data.summary }) + '\n');
      } else {
        console.log(`[sigmap] dashboard written: ${path.relative(cwd, outPath)}`);
      }
    } catch (err) {
      console.error(`[sigmap] dashboard error: ${err.message}`);
      process.exit(1);
    }
    process.exit(0);
  }

  if (args.includes('--suggest-tool')) {
    const idx = args.indexOf('--suggest-tool');
    const taskDesc = (args[idx + 1] || '').trim();
    if (!taskDesc || taskDesc.startsWith('--')) {
      console.error('[sigmap] --suggest-tool requires a task description');
      console.error('  Example: node gen-context.js --suggest-tool "refactor the auth module"');
      process.exit(1);
    }
    const result = suggestTool(taskDesc);
    if (args.includes('--json')) {
      process.stdout.write(JSON.stringify(result) + '\n');
    } else {
      console.log('[sigmap] suggest-tool:');
      console.log(`  tier   : ${result.tier}`);
      console.log(`  label  : ${result.label}`);
      console.log(`  models : ${result.models}`);
      console.log(`  cost   : ${result.costHint}`);
    }
    process.exit(0);
  }

  if (args.includes('--benchmark') || args.includes('--eval')) {
    try {
      const { run, formatTable, formatMetrics } = __require('./src/eval/runner');
      const tasksFile = path.join(cwd, 'benchmarks', 'tasks', 'retrieval.jsonl');
      const result = run(tasksFile, cwd, { topK: 10 });
      if (args.includes('--json')) {
        // Compact output: strip ranked arrays to keep payload small
        const compact = {
          metrics: result.metrics,
          tasks: result.tasks.map((t) => ({
            id: t.id,
            query: t.query,
            hit5: t.hit5,
            rr: t.rr,
            precAt5: t.precAt5,
            tokens: t.tokens,
            top1: t.ranked[0] || null,
          })),
        };
        process.stdout.write(JSON.stringify(compact) + '\n');
      } else {
        console.log(formatMetrics(result.metrics));
        if (result.tasks.length > 0) {
          console.log('');
          console.log(formatTable(result.tasks));
        }
      }
    } catch (err) {
      console.error(`[sigmap] benchmark error: ${err.message}`);
      process.exit(1);
    }
    process.exit(0);
  }

  if (args.includes('--analyze')) {
    try {
      const { analyzeFiles, formatAnalysisTable, formatAnalysisJSON } = requireSourceOrBundled('./src/eval/analyzer');
      const cfg    = config || {};
      const srcDirs = cfg.srcDirs || DEFAULTS.srcDirs;
      const exclude = cfg.exclude || DEFAULTS.exclude;
      const slow    = args.includes('--slow');

      // Collect files (reuse existing file-walker if accessible, else inline)
      const allFiles = [];
      function walkForAnalyze(dir, depth) {
        if (depth > (cfg.maxDepth || 6)) return;
        let entries;
        try { entries = fs.readdirSync(dir, { withFileTypes: true }); } catch (_) { return; }
        for (const e of entries) {
          if (exclude.some((x) => e.name === x || e.name.startsWith(x))) continue;
          const full = path.join(dir, e.name);
          if (e.isDirectory()) walkForAnalyze(full, depth + 1);
          else if (e.isFile()) allFiles.push(full);
        }
      }
      for (const sd of srcDirs) {
        const abs = path.join(cwd, sd);
        if (fs.existsSync(abs)) walkForAnalyze(abs, 0);
      }

      const stats = analyzeFiles(allFiles, cwd, { slow, maxSigs: cfg.maxSigsPerFile || 25 });

      if (args.includes('--json')) {
        const out = JSON.stringify(formatAnalysisJSON(stats)) + '\n';
        // Use the write callback to exit only after the OS has accepted all
        // bytes. Calling process.exit(0) synchronously after write() truncates
        // large outputs because the underlying pipe write is asynchronous even
        // when write() returns true.
        process.stdout.write(out, 'utf8', () => process.exit(0));
        return; // exit is handled by the callback above
      } else {
        const table = formatAnalysisTable(stats, slow);
        process.stdout.write(table);
      }
    } catch (err) {
      console.error(`[sigmap] analyze error: ${err.message}`);
      process.exit(1);
    }
    process.exit(0);
  }

  if (args.includes('--diagnose-extractors')) {
    try {
      const fixturesDir = path.join(cwd, 'test', 'fixtures');
      const expectedDir = path.join(cwd, 'test', 'expected');
      if (!fs.existsSync(fixturesDir) || !fs.existsSync(expectedDir)) {
        console.error('[sigmap] test/fixtures or test/expected not found — run from the SigMap repo root');
        process.exit(1);
      }

      const EXT_TO_LANG = {
        '.ts': 'typescript', '.js': 'javascript', '.py': 'python',
        '.java': 'java', '.kt': 'kotlin', '.go': 'go', '.rs': 'rust',
        '.cs': 'csharp', '.cpp': 'cpp', '.rb': 'ruby', '.php': 'php',
        '.swift': 'swift', '.dart': 'dart', '.scala': 'scala',
        '.r': 'r', '.R': 'r',
        '.vue': 'vue', '.svelte': 'svelte', '.html': 'html',
        '.css': 'css', '.yml': 'yaml', '.sh': 'shell',
      };
      const SPECIAL = { 'Dockerfile': 'dockerfile' };

      let passed = 0; let failed = 0;
      const entries = fs.readdirSync(fixturesDir).sort();

      for (const filename of entries) {
        const ext  = path.extname(filename).toLowerCase();
        const lang = EXT_TO_LANG[ext] || SPECIAL[filename];
        if (!lang) continue;

        const fixturePath = path.join(fixturesDir, filename);
        const expectedPath = path.join(expectedDir, `${lang}.txt`);
        if (!fs.existsSync(expectedPath)) {
          console.log(`  SKIP  ${lang.padEnd(12)} (no expected file)`);
          continue;
        }

        const src      = fs.readFileSync(fixturePath, 'utf8');
        const expected = fs.readFileSync(expectedPath, 'utf8').trim();

        let mod;
        try {
          mod = requireSourceOrBundled(`./src/extractors/${lang}`);
        } catch (e) {
          console.log(`  ERROR ${lang.padEnd(12)} loader failed: ${e.message}`);
          failed++;
          continue;
        }

        let actual;
        try {
          const sigs = mod.extract(src);
          actual = sigs.join('\n').trim();
        } catch (e) {
          console.log(`  ERROR ${lang.padEnd(12)} extract() threw: ${e.message}`);
          failed++;
          continue;
        }

        if (actual === expected) {
          console.log(`  PASS  ${lang}`);
          passed++;
        } else {
          console.log(`  FAIL  ${lang}`);
          // Show first diff line
          const aLines = actual.split('\n');
          const eLines = expected.split('\n');
          const maxLen = Math.max(aLines.length, eLines.length);
          for (let i = 0; i < maxLen; i++) {
            if (aLines[i] !== eLines[i]) {
              console.log(`         expected: ${(eLines[i] || '(missing)').slice(0, 100)}`);
              console.log(`         actual  : ${(aLines[i] || '(missing)').slice(0, 100)}`);
              break;
            }
          }
          failed++;
        }
      }

      console.log(`\n${passed} passed, ${failed} failed`);
      process.exit(failed > 0 ? 1 : 0);
    } catch (err) {
      console.error(`[sigmap] diagnose error: ${err.message}`);
      process.exit(1);
    }
  }

  if (args.includes('--query')) {
    try {
      const qIdx = args.indexOf('--query');
      const query = (args[qIdx + 1] || '').trim();
      if (!query || query.startsWith('--')) {
        console.error('[sigmap] --query requires a search string');
        console.error('  Example: node gen-context.js --query "add a new language extractor"');
        process.exit(1);
      }
      const { rank, buildSigIndex, formatRankTable, formatRankJSON } = requireSourceOrBundled('./src/retrieval/ranker');

      // Resolve the context file path to query against.
      // Priority: --output flag > --adapter flag > buildSigIndex probe order
      //   (customOutput from config is handled inside buildSigIndex itself)
      let queryOpts;
      const adpIdx = args.indexOf('--adapter');

      // 1. --output <file> pins to an explicit path
      if (config.customOutput) {
        queryOpts = { contextPath: path.resolve(cwd, config.customOutput) };
      }

      // 2. --adapter <name> pins to that adapter's output path (if --output not given)
      if (!queryOpts && adpIdx >= 0) {
        const adapterName = (args[adpIdx + 1] || '').trim().toLowerCase();
        const VALID_ADAPTERS = ['copilot', 'claude', 'cursor', 'windsurf', 'openai', 'gemini', 'codex'];
        if (VALID_ADAPTERS.includes(adapterName)) {
          try {
            const adapterMod = __require('./packages/adapters/' + adapterName);
            queryOpts = { contextPath: adapterMod.outputPath(cwd) };
          } catch (_) {}
        }
      }

      const index = buildSigIndex(cwd, queryOpts);
      if (index.size === 0) {
        console.error('[sigmap] no context file found. Run: node gen-context.js');
        if (adpIdx >= 0) {
          console.error('  (tried the path for --adapter ' + (args[adpIdx + 1] || '') + ')');
        }
        process.exit(1);
      }
      const topIdx = args.indexOf('--top');
      const topK = topIdx >= 0 ? Math.min(Math.max(1, parseInt(args[topIdx + 1], 10) || 10), 25)
                               : ((config && config.retrieval && config.retrieval.topK) || 10);
      const recencyBoost = (config && config.retrieval && config.retrieval.recencyBoost) || 1.5;
      const results = rank(query, index, { topK, recencyBoost, cwd });
      if (args.includes('--context')) {
        const miniCtx  = buildMiniContext(results, cwd);
        const ctxOut   = path.join(cwd, '.context', 'query-context.md');
        fs.mkdirSync(path.dirname(ctxOut), { recursive: true });
        fs.writeFileSync(ctxOut, miniCtx, 'utf8');
        console.log(`[sigmap] query context → ${path.relative(cwd, ctxOut)}  (${estimateTokens(miniCtx)} tokens)`);
      } else if (args.includes('--json')) {
        process.stdout.write(JSON.stringify(formatRankJSON(results, query)) + '\n');
      } else {
        process.stdout.write(formatRankTable(results, query));
      }
    } catch (err) {
      console.error(`[sigmap] query error: ${err.message}`);
      process.exit(1);
    }
    process.exit(0);
  }

  // ── --each [--adapter <name>] ────────────────────────────────────────────
  // Must be checked before --adapter so that --each --adapter <name> is
  // handled here (per-repo) rather than running a single generate on the
  // parent directory.
  if (args.includes('--each')) {
    const VALID_ADAPTERS = ['copilot', 'claude', 'cursor', 'windsurf', 'openai', 'gemini', 'codex'];
    const adpIdx = args.indexOf('--adapter');
    const adapterOverride = adpIdx >= 0 ? (args[adpIdx + 1] || '').trim().toLowerCase() : null;
    if (adapterOverride && !VALID_ADAPTERS.includes(adapterOverride)) {
      console.error(`[sigmap] --each: unknown adapter "${adapterOverride}"`);
      console.error(`  Valid adapters: ${VALID_ADAPTERS.join(', ')}`);
      process.exit(1);
    }
    runEach(cwd, config, adapterOverride || null);
    process.exit(0);
  }

  // ── --adapter <name> ───────────────────────────────────────────────────────
  if (args.includes('--adapter')) {
    try {
      const adpIdx = args.indexOf('--adapter');
      const adapterName = (args[adpIdx + 1] || '').trim().toLowerCase();
      const VALID_ADAPTERS = ['copilot', 'claude', 'cursor', 'windsurf', 'openai', 'gemini', 'codex'];
      if (!adapterName || adapterName.startsWith('--')) {
        console.error('[sigmap] --adapter requires an adapter name');
        console.error(`  Valid adapters: ${VALID_ADAPTERS.join(', ')}`);
        console.error('  Example: node gen-context.js --adapter copilot');
        process.exit(1);
      }
      if (!VALID_ADAPTERS.includes(adapterName)) {
        console.error(`[sigmap] unknown adapter: "${adapterName}"`);
        console.error(`  Valid adapters: ${VALID_ADAPTERS.join(', ')}`);
        process.exit(1);
      }
      if (args.includes('--json')) {
        const adapterMod = __require('./packages/adapters/' + adapterName);
        const outPath = adapterMod.outputPath(cwd);
        process.stdout.write(JSON.stringify({ adapter: adapterName, outputPath: outPath, version: VERSION }) + '\n');
        process.exit(0);
      }
      // Run generate with this adapter's output targets
      const singleAdapterConfig = Object.assign({}, config, {
        outputs: adapterName === 'claude' ? ['claude'] : [adapterName],
        adapters: [adapterName],
      });
      runGenerate(cwd, singleAdapterConfig, false);
      const adapterMod = __require('./packages/adapters/' + adapterName);
      console.warn(`[sigmap] adapter "${adapterName}" → ${path.relative(cwd, adapterMod.outputPath(cwd))}`);
    } catch (err) {
      console.error(`[sigmap] adapter error: ${err.message}`);
      process.exit(1);
    }
    process.exit(0);
  }

  // ── --impact <file> ────────────────────────────────────────────────────────
  if (args.includes('--impact')) {
    try {
      const impIdx = args.indexOf('--impact');
      const targetFile = (args[impIdx + 1] || '').trim();
      if (!targetFile || targetFile.startsWith('--')) {
        console.error('[sigmap] --impact requires a file path');
        console.error('  Example: node gen-context.js --impact src/extractors/python.js');
        process.exit(1);
      }
      const { analyzeImpact, formatImpact, formatImpactJSON } = requireSourceOrBundled('./src/graph/impact');
      const depthIdx = args.indexOf('--depth');
      const depth = depthIdx >= 0 ? Math.max(0, parseInt(args[depthIdx + 1], 10) || 3) : ((config && config.impact && config.impact.depth) || 3);
      const results = analyzeImpact(targetFile, cwd, { depth });
      if (args.includes('--json')) {
        const out = results.map((r) => formatImpactJSON(r.impact));
        process.stdout.write(JSON.stringify(out.length === 1 ? out[0] : out) + '\n');
      } else {
        for (const r of results) {
          process.stdout.write(formatImpact(r.impact) + '\n');
        }
      }
    } catch (err) {
      console.error(`[sigmap] impact error: ${err.message}`);
      process.exit(1);
    }
    process.exit(0);
  }

  if (args.includes('--report')) {
    if (args.includes('--history')) {
      try {
        const { readLog, summarize } = __require('./src/tracking/logger');
        const entries = readLog(cwd);
        const summary = summarize(entries);
        let chartInfo = null;
        if (args.includes('--chart')) {
          const { score } = __require('./src/health/scorer');
          const { renderHistoryCharts } = requireSourceOrBundled('./src/format/dashboard');
          chartInfo = renderHistoryCharts(cwd, score(cwd));
        }
        if (args.includes('--json')) {
          const payload = chartInfo
            ? {
                ...summary,
                chart: {
                  tokenReductionSparkline: chartInfo.tokenReductionSparkline,
                  hitAt5Sparkline: chartInfo.hitAt5Sparkline,
                  summary: chartInfo.summary,
                  charts: chartInfo.charts,
                },
              }
            : summary;
          process.stdout.write(JSON.stringify(payload) + '\n');
        } else {
          console.log('[sigmap] usage history:');
          console.log(`  total runs      : ${summary.totalRuns}`);
          console.log(`  avg reduction   : ${summary.avgReductionPct}%`);
          console.log(`  avg tokens out  : ~${summary.avgFinalTokens}`);
          console.log(`  over-budget runs: ${summary.overBudgetRuns}`);
          if (summary.firstRun) console.log(`  first run       : ${summary.firstRun}`);
          if (summary.lastRun)  console.log(`  last run        : ${summary.lastRun}`);
          if (chartInfo) {
            console.log('');
            console.log(chartInfo.text);
          }
        }
      } catch (err) {
        console.warn(`[sigmap] tracking: ${err.message}`);
      }
      process.exit(0);
    }
    runGenerate(cwd, config, true, args.includes('--json'));
    process.exit(0);
  }

  if (args.includes('--monorepo') || config.monorepo) {
    runMonorepo(cwd, config);
    process.exit(0);
  }

  if (args.includes('--setup')) {
    runGenerate(cwd, config, false);
    installHook(cwd, scriptPath);
    registerMcp(cwd, scriptPath);
    watchMode(cwd, config);
    return; // keep process alive for watch
  }

  if (args.includes('--watch')) {
    runGenerate(cwd, config, false);
    watchMode(cwd, config);
    return; // keep process alive
  }

  if (args.includes('--diff')) {
    const idx = args.indexOf('--diff');
    const maybeBase = args[idx + 1];
    const baseRef = (maybeBase && !maybeBase.startsWith('--')) ? maybeBase : null;
    runDiff(cwd, config, args.includes('--staged'), baseRef);
    process.exit(0);
  }

  // v4.2: `--cost` — show token/$ cost estimate before and after SigMap
  if (args.includes('--cost')) {
    const rawTok = getRawTokenCount(cwd, config);
    runGenerate(cwd, config, false);

    const model = args[args.indexOf('--model') + 1] || 'gpt-4o';
    const rateK = MODEL_COSTS[model] || MODEL_COSTS['gpt-4o'];

    const ctxPath = config.customOutput
      ? path.resolve(cwd, config.customOutput)
      : path.join(cwd, '.github', 'copilot-instructions.md');
    let outTok = 0;
    try { outTok = estimateTokens(fs.readFileSync(ctxPath, 'utf8')); } catch (_) {}

    const savings = rawTok > 0 ? Math.round((1 - outTok / rawTok) * 100) : 0;
    const costRaw = (rawTok / 1000) * rateK;
    const costCtx = (outTok / 1000) * rateK;

    const out = {
      model,
      rawTokens:     rawTok,
      contextTokens: outTok,
      costRaw:       costRaw.toFixed(4),
      costContext:   costCtx.toFixed(4),
      savingsPct:    savings,
    };

    if (args.includes('--json')) {
      process.stdout.write(JSON.stringify(out) + '\n');
    } else {
      console.log(`\n Cost estimate (${model}):`);
      console.log(` Without SigMap : ${rawTok.toLocaleString()} tok  $${out.costRaw}/query`);
      console.log(` With SigMap    : ${outTok.toLocaleString()} tok  $${out.costContext}/query`);
      console.log(` Savings        : ${savings}%  ($${(costRaw - costCtx).toFixed(4)} saved per query)\n`);
    }
    process.exit(0);
  }

  // v4.3: `--ci [--min-coverage N] [--json]` — GitHub Actions exit gate
  if (args.includes('--ci')) {
    const minCovIdx = args.indexOf('--min-coverage');
    const minCoverage = minCovIdx !== -1 ? Math.max(0, Math.min(100, parseInt(args[minCovIdx + 1], 10) || 80)) : 80;

    // Coverage = files actually in context / total source files
    const { buildSigIndex: ciBuildSigIndex } = requireSourceOrBundled('./src/retrieval/ranker');
    const ciSigIndex  = ciBuildSigIndex(cwd);
    const ciTotal     = buildFileList(cwd, config).length;
    const coveragePct = ciTotal > 0 ? Math.round((ciSigIndex.size / ciTotal) * 100) : 0;

    const pass = coveragePct >= minCoverage;

    if (args.includes('--json')) {
      process.stdout.write(JSON.stringify({ pass, coverage: coveragePct, threshold: minCoverage }) + '\n');
    } else if (pass) {
      console.log(`[sigmap] ✓ CI gate passed — coverage ${coveragePct}% ≥ ${minCoverage}%`);
    } else {
      console.error(`[sigmap] ✗ CI gate FAILED — coverage ${coveragePct}% < ${minCoverage}%`);
      console.error(`  Fix: increase maxTokens or expand srcDirs in gen-context.config.json`);
    }
    process.exit(pass ? 0 : 1);
  }

  // Default: generate once
  runGenerate(cwd, config, false);
}

main();
